public record ShipmentDetails(
    string TrackingNumber,
    string Status,
    string Location,
    DateTimeOffset EstimatedDelivery,
    IReadOnlyList<StatusUpdate> Updates);

public record StatusUpdate(DateTimeOffset Timestamp, string Description, string Location);

using sv_69ade8f8aac44058bfce05e94d8e493a.Client.Models;

namespace sv_69ade8f8aac44058bfce05e94d8e493a.Client.Services;

public interface IShipmentService
{
    Task<ShipmentDetails?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using System.Net.Http.Json;
using sv_69ade8f8aac44058bfce05e94d8e493a.Client.Models;

namespace sv_69ade8f8aac44058bfce05e94d8e493a.Client.Services;

/// <summary>
/// Client-side implementation that calls the server API (used when running on WebAssembly).
/// </summary>
public class HttpShipmentService(HttpClient http) : IShipmentService
{
    public async Task<ShipmentDetails?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await http.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
            return null;

        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<ShipmentDetails>(ct);
    }
}

