/// <summary>
/// Server-side implementation that simulates a slow backend with seeded data.
/// </summary>
public class ServerShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new ShipmentDetails(
            TrackingNumber: "PKG-001",
            Status: "In Transit",
            Location: "Chicago, IL",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 28, 17, 0, 0, TimeSpan.FromHours(-5)),
            Updates:
            [
                new StatusUpdate(new DateTimeOffset(2026, 5, 23, 8, 0, 0, TimeSpan.FromHours(-5)), "Package picked up", "New York, NY"),
                new StatusUpdate(new DateTimeOffset(2026, 5, 24, 14, 30, 0, TimeSpan.FromHours(-5)), "Arrived at sorting facility", "Philadelphia, PA"),
                new StatusUpdate(new DateTimeOffset(2026, 5, 25, 6, 15, 0, TimeSpan.FromHours(-6)), "Departed facility", "Chicago, IL"),
            ]),

        ["PKG-002"] = new ShipmentDetails(
            TrackingNumber: "PKG-002",
            Status: "Delivered",
            Location: "San Francisco, CA",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 24, 12, 0, 0, TimeSpan.FromHours(-7)),
            Updates:
            [
                new StatusUpdate(new DateTimeOffset(2026, 5, 21, 9, 0, 0, TimeSpan.FromHours(-7)), "Package picked up", "Los Angeles, CA"),
                new StatusUpdate(new DateTimeOffset(2026, 5, 22, 11, 0, 0, TimeSpan.FromHours(-7)), "In transit", "Bakersfield, CA"),
                new StatusUpdate(new DateTimeOffset(2026, 5, 23, 16, 45, 0, TimeSpan.FromHours(-7)), "Out for delivery", "San Francisco, CA"),
                new StatusUpdate(new DateTimeOffset(2026, 5, 24, 10, 20, 0, TimeSpan.FromHours(-7)), "Delivered", "San Francisco, CA"),
            ]),

        ["PKG-003"] = new ShipmentDetails(
            TrackingNumber: "PKG-003",
            Status: "Processing",
            Location: "Dallas, TX",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 30, 18, 0, 0, TimeSpan.FromHours(-5)),
            Updates:
            [
                new StatusUpdate(new DateTimeOffset(2026, 5, 25, 7, 0, 0, TimeSpan.FromHours(-5)), "Label created", "Dallas, TX"),
            ]),
    };

    public async Task<ShipmentDetails?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        // Simulate slow backend
        await Task.Delay(1500, ct);

        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

