@page "/shipments/{TrackingNumber}"
@using sv_69ade8f8aac44058bfce05e94d8e493a.Client.Models
@using sv_69ade8f8aac44058bfce05e94d8e493a.Client.Services
@rendermode InteractiveAuto
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Track Shipment - @TrackingNumber</PageTitle>

<h2>Shipment Tracking</h2>

@if (_loading)
{
    <div class="loading-placeholder">
        <p><em>Loading shipment details for <strong>@TrackingNumber</strong>...</em></p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="alert alert-warning">
        <p>No shipment found for tracking number <strong>@TrackingNumber</strong>.</p>
    </div>
}
else
{
    <div class="shipment-details">
        <dl>
            <dt>Tracking Number</dt>
            <dd>@_shipment.TrackingNumber</dd>

            <dt>Status</dt>
            <dd>@_shipment.Status</dd>

            <dt>Current Location</dt>
            <dd>@_shipment.Location</dd>

            <dt>Estimated Delivery</dt>
            <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
        </dl>

        <h4>Status Updates</h4>
        @if (_shipment.Updates.Count == 0)
        {
            <p>No status updates available.</p>
        }
        else
        {
            <table class="table">
                <thead>
                    <tr>
                        <th>Time</th>
                        <th>Description</th>
                        <th>Location</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var update in _shipment.Updates)
                    {
                        <tr>
                            <td>@update.Timestamp.ToString("g")</td>
                            <td>@update.Description</td>
                            <td>@update.Location</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    private ShipmentDetails? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any previous in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _loading = true;
        _errorMessage = null;
        _shipment = null;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed — silently stop
            return;
        }
        catch (TaskCanceledException)
        {
            Logger.LogError("Timeout while loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TimeoutException)
        {
            Logger.LogError("Timeout while loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Failed to load shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task RetryAsync()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

